const rawInput = ($node["When Chat Message Received"].json.chatInput || '').trim();

// Normalize input
const input = rawInput
  .replace(/^(do\s+)?(osint|research|analyze|lookup)\s+(on\s+)?/i, '')
  .trim();

// ✅ FIXED regex (added dot support)
const fromPattern = /^([\w\s\-]+?)\s+(?:from|at)\s+([\w.\-]+)$/i;
const fromMatch = input.match(fromPattern);

let employeeName = '';
let company = '';
let hasEmployee = false;

if (fromMatch) {
  employeeName = fromMatch[1].trim();
  company = fromMatch[2].trim();
  hasEmployee = true;
} else {
  // fallback
  if (/company:|org:/i.test(input)) {
    const parts = input.split(/company:|org:/i);
    if (parts.length > 1) {
      company = parts[1].trim().split(/\s+/)[0];
      employeeName = parts[0].trim();
      hasEmployee = true;
    }
  }
}

return [{
  json: {
    company: company.toLowerCase(),
    employeeName,
    hasEmployee,
    originalInput: rawInput
  }
}];

const users = Array.isArray($json.items) ? $json.items : [];
const profiles = users.slice(0, 3).map(u => ({
  username: u.login,
  profile_url: u.html_url,
  avatar: u.avatar_url,
  repositories_count: u.public_repos
}));
return [{ json: { github_profiles: profiles } }];

const results = Array.isArray($json.organic_results) ? $json.organic_results : [];
const profiles = results.filter(r => r.link && r.link.includes('linkedin.com')).slice(0, 3).map(r => ({
  name: r.title || 'Unknown',
  url: r.link || '',
  snippet: r.snippet || ''
}));
return [{ json: { linkedin_profiles: profiles } }];

const res = Array.isArray($json.organic_results) ? $json.organic_results : [];

const profiles = res
  .map(r => {
    const url = (r.link || r.redirect_link || '').toLowerCase();
    if (!url) return null;

    return {
      title: r.title || '',
      link: url,
      snippet: r.snippet || ''
    };
  })
  .filter(r => {
    if (!r) return false;

    const url = r.link;

    return (
      // ✅ LinkedIn profiles only
      (url.includes('linkedin.com/in/') || url.includes('linkedin.com/company/')) ||

      // ✅ Twitter/X
      url.includes('twitter.com/') ||
      url.includes('x.com/')
    );
  })
  .filter(r => {
    // ❌ remove garbage
    return (
      !r.link.includes('/posts/') &&
      !r.link.includes('/activity/') &&
      !r.link.includes('google.com/url')
    );
  })
  // ✅ dedupe
  .filter((v, i, arr) => arr.findIndex(x => x.link === v.link) === i)
  .slice(0, 5);

return [{
  json: {
    social_profiles: profiles
  }
}];

const allInputs = $input.all();
const osintData = (allInputs[0]?.json || {});
const companyProfile = (allInputs[1]?.json || {});
const companyName = $node["Parse Company"].json.company;
return [{ json: { company: companyName, osintSearches: osintData, companyProfile: companyProfile } }];

return [{
  json: {
    profileSummary: $json.choices?.[0]?.message?.content || 'OSINT analysis complete'
  }
}];

const emails = Array.isArray($json.data?.emails) ? $json.data.emails : [];
const discovered = emails.slice(0, 5).map(e => ({ email: e.value, name: e.first_name + ' ' + e.last_name, verified: e.verified }));
return [{ json: { hunter_emails: discovered } }];

const raw = $json.scanOutput || $json.chatOutput || ($json.choices?.[0]?.message?.content) || 'No analysis available.';
const ts = new Date().toISOString().replace('T', ' ').slice(0, 19) + ' UTC';
const divider = '═'.repeat(43);
const line = '─'.repeat(43);
const report = divider + '
🌐  AI SECURITY ANALYSIS REPORT
' + divider + '

🕐 Generated: ' + ts + '
🔒 Classification: FOR AUTHORIZED USE ONLY

' + line + '

' + raw + '

' + line + '
📌 Report generated via n8n Unified AI Pipeline
⚠️  This report is for authorized penetration testing purposes only.
' + divider;
return [{ json: { output: report } }];

const inputRaw = $node["When Chat Message Received"].json.chatInput || "";
const input = inputRaw.trim();

// Normalize
const clean = input.replace(/\s+/g, ' ');

// Flags
const isAggressive = /aggressive/i.test(clean);
const scanType = isAggressive ? 'aggressive' : 'normal';

let target = null;

// 1️⃣ Extract IP (strict)
let match = clean.match(/\b((25[0-5]|2[0-4]\d|1\d\d|[1-9]?\d)(\.(?!$)|$)){4}\b/);

// 2️⃣ Extract URL (http/https)
if (!match) {
  const urlMatch = clean.match(/https?:\/\/([^\/\s]+)/i);
  if (urlMatch) {
    target = urlMatch[1];
  }
}

// 3️⃣ Extract domain (proper FQDN)
if (!match && !target) {
  match = clean.match(/\b([a-zA-Z0-9-]+\.)+[a-zA-Z]{2,}\b/);
}

// 4️⃣ Keywords like: scan / target / host
if (!match && !target) {
  const keywordMatch = clean.match(/(?:scan|target|host)\s+([a-zA-Z0-9.-]+)/i);
  if (keywordMatch) {
    target = keywordMatch[1];
  }
}

// 5️⃣ Fallback → find last valid token (NOT random words like "scan")
if (!match && !target) {
  const tokens = clean.split(/\s+/).reverse();
  for (const token of tokens) {
    if (
      /^[a-zA-Z0-9.-]+$/.test(token) &&   // valid chars
      token.includes('.') &&             // must look like domain
      !/^(scan|run|do|check)$/i.test(token) // avoid verbs
    ) {
      target = token;
      break;
    }
  }
}

// Final assignment
if (!target && match) {
  target = match[0];
}

// Cleanup
if (target) {
  target = target
    .replace(/^https?:\/\//, '')
    .replace(/\/$/, '')
    .replace(/[^a-zA-Z0-9.-]/g, '');
}

return [{
  json: {
    target,
    scanType,
    isAggressive
  }
}];

const data = $input.first().json;
let hosts = [];

if (data.nmaprun && data.nmaprun.host) {
    const hostList = Array.isArray(data.nmaprun.host) ? data.nmaprun.host : [data.nmaprun.host];

    hostList.forEach(host => {
        if (host.status && host.status.state === 'up') {
            const hostInfo = { ip: host.address.addr, ports: [] };

            if (host.ports && host.ports.port) {
                const ports = Array.isArray(host.ports.port) ? host.ports.port : [host.ports.port];

                ports.forEach(p => {
                    if (p.state && p.state.state === 'open') {
                        // Gather Service Info: Use product/version if name is tcpwrapped
                        const sName = p.service ? p.service.name : 'unknown';
                        const product = p.service ? (p.service.product || '') : '';
                        const version = p.service ? (p.service.version || '') : '';

                        // Extract Script Output (useful for identifying real services on tcpwrapped ports)
                        let scriptData = "";
                        if (p.script) {
                            const scripts = Array.isArray(p.script) ? p.script : [p.script];
                            scriptData = scripts.map(s => `${s.id}: ${s.output}`).join(' | ');
                        }

                        hostInfo.ports.push({ 
                            port: p.portid, 
                            service: sName,
                            details: `${product} ${version}`.trim(),
                            scripts: scriptData
                        });
                    }
                });
            }
            hosts.push(hostInfo);
        }
    });
}
return [{ json: { hosts, total: hosts.length } }];

const aiResponse = $input.first().json;

return [{
  json: {
    scanOutput: aiResponse.choices?.[0]?.message?.content || 'Scan complete.'
  }
}];

const input = ($node["When Chat Message Received"].json.chatInput || "").trim();
const clean = input.replace(/\s+/g, ' ');

let username = null;

// 1️⃣ GitHub URL (handles query params, trailing slash)
let match = clean.match(/github\.com\/([a-zA-Z0-9-_]+)/i);

// 2️⃣ github: username / github username / github = username
if (!match) {
  match = clean.match(/github[\s:=]+@?([a-zA-Z0-9-_]+)/i);
}

// 3️⃣ Phrases like: "github profile USERNAME"
if (!match) {
  match = clean.match(/github\s+(?:profile|user)?\s*@?([a-zA-Z0-9-_]+)/i);
}

// 4️⃣ @username anywhere
if (!match) {
  match = clean.match(/@([a-zA-Z0-9-_]+)/);
}

// 5️⃣ Fallback → last valid token in sentence
if (!match) {
  const tokens = clean.split(/\s+/).reverse();
  for (const token of tokens) {
    if (/^[a-zA-Z0-9-_]+$/.test(token)) {
      username = token;
      break;
    }
  }
} else {
  username = match[1];
}

// 6️⃣ Final cleanup
if (username) {
  username = username
    .replace(/^@/, '')
    .replace(/\/$/, '')
    .replace(/[^a-zA-Z0-9-_]/g, '');
}

return [{ json: { username } }];

const rawItems = $input.all().map(i => i.json);
const repos = rawItems.length === 1 && Array.isArray(rawItems[0]) ? rawItems[0] : rawItems;

return repos
  .filter(r => r && r.owner && r.owner.login && r.name)
  .map(r => ({
    json: {
      owner: r.owner.login,
      repo: r.name,
    }
  }));

const rawItems = $input.all().map(i => i.json);
const commits = rawItems.length === 1 && Array.isArray(rawItems[0]) ? rawItems[0] : rawItems;

const emails = new Set();

for (const c of commits) {
  const email = c?.commit?.author?.email;
  if (email && !email.includes('noreply')) {
    emails.add(email);
  }
}

return [{ json: { emails: Array.from(emails) } }];

