if ($json.hasEmployee && $json.employeeName && $json.company) {
  return [{ json: { employeeName: $json.employeeName.trim(), company: $json.company.trim(), hasEmployee: true } }];
}
return [];

let company = ($json.company || '').trim().toLowerCase();

// already a domain → keep it
if (/^[a-z0-9.-]+\.[a-z]{2,}$/.test(company)) {
  return [{ json: { ...$json, domain: company } }];
}

// convert company name → domain (basic fallback)
const cleaned = company.replace(/[^a-z0-9]/g, '');
return [{ json: { ...$json, domain: cleaned + '.com' } }];
